{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/YankeeMustDie.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class YankeeMustDie < Base\n      # ゲームシステムの識別子\n      ID = \"YankeeMustDie\"\n\n      # ゲームシステム名\n      NAME = \"ヤンキーマストダイ\"\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = \"やんきいますとたい\"\n\n      HELP_MESSAGE = <<~TEXT\n        ■ 判定の方法\n          基本形式：\n          (YD+a>=b) または (YD+a>b)\n          a：能力値、技能レベル、ドウグ等による修正値(複数指定可)\n          b：目標となる成功段階\n\n        ■ 成功の条件\n          >=b：目標となる成功段階b以上の場合に成功となります。この条件では、目標となる成功段階と同じ数値でも成功とみなされます。\n          >b：目標となる成功段階bより高い成功段階を出した場合に成功となります。この条件では、目標となる成功段階と同じ数値では失敗となります。\n\n        ■ 各種表\n        　関係表 RT\n        　場面表 ST\n        　ハプニング表 HT\n        　闇堕ち表 DT\n      TEXT\n\n      def initialize(command)\n        super(command)\n        @sort_barabara_dice = true\n        @sides_implicit_d = 10\n      end\n\n      def eval_game_system_specific_command(command)\n        return check_action(command) || roll_tables(command, TABLES)\n      end\n\n      def check_action(command)\n        parser = Command::Parser.new(\"YD\", round_type: @round_type)\n                                .restrict_cmp_op_to(:>=, :>, nil)\n        parsed = parser.parse(command)\n        unless parsed\n          return nil\n        end\n\n        dice_all = []\n        loop do\n          dice_list = @randomizer.roll_barabara(3, 10).sort\n          dice_all.push(dice_list)\n          break unless dice_list.uniq.one?\n        end\n\n        achievement_value = dice_all.flatten.sum(parsed.modify_number)\n        if achievement_value <= 9\n          success_level = 0\n        elsif achievement_value <= 19\n          success_level = 1\n        elsif achievement_value <= 29\n          success_level = 2\n        elsif achievement_value <= 39\n          success_level = 3\n        elsif achievement_value <= 49\n          success_level = 4\n        elsif achievement_value <= 59\n          success_level = 5\n        elsif achievement_value <= 69\n          success_level = 6\n        elsif achievement_value <= 79\n          success_level = 7\n        elsif achievement_value <= 89\n          success_level = 8\n        elsif achievement_value <= 99\n          success_level = 9\n        else\n          success_level = 10\n        end\n\n        if parsed.cmp_op == :>\n          is_success = success_level > parsed.target_number\n          is_failure = !is_success\n          success_message = is_success ? '成功' : '失敗'\n        elsif parsed.cmp_op == :>=\n          is_success = success_level >= parsed.target_number\n          is_failure = !is_success\n          success_message = is_success ? '成功' : '失敗'\n        else\n          is_success = false\n          is_failure = false\n          success_message = nil\n        end\n\n        dice_to_message_arr = []\n        dice_all.each do |arr|\n          dice_to_message_arr.append(\"\#{arr.sum}[\#{arr.join(',')}]\")\n        end\n\n        sequence = [\n          parsed.to_s,\n          format(\"\#{dice_to_message_arr.join(' + ')} %+d\", parsed.modify_number),\n          achievement_value,\n          \"成功段階\#{success_level}\"\n        ]\n\n        if success_message\n          sequence.append(success_message)\n        end\n\n        Result.new.tap do |r|\n          r.text = sequence.join(\" ＞ \")\n          r.success = is_success\n          r.failure = is_failure\n        end\n      end\n\n      TABLES = {\n        'RT' => DiceTable::Table.new(\n          '関係表',\n          '1D10',\n          [\n            'マブダチ：相手とは、マブダチ（親友） だ。いつからマブダチなのかはプレイヤー同士で相談して決めること。',\n            '先輩／後輩：相手とは、先輩と後輩の間柄だ。なんの先輩後輩かはプレイヤー同士で相談して決めること。',\n            '兄弟：相手とは、血縁であったり契りを交わした兄弟だ。兄弟になった経緯はプレイヤー同士で相談して決めること。',\n            'ライバル：相手とは、良きライバル関係にある。どのようなライバル関係かはプレイヤー同士で相談して決めること。',\n            '仲間：相手とは、同じチームなどに所属している仲間だ。どんなチームかはプレイヤー同士で相談して決めること。',\n            'ジモティー：相手とは、同じ地元の仲間、幼馴染だ。いつから幼馴染なのかはプレイヤー同士で相談して決めること。',\n            'おな中：相手とは、出身中学（小学校・高校も可） が同じだ。どんな中学だったのかはプレイヤー同士で決めること。',\n            '相棒：相手は、唯一無二の相棒だ。いつから相棒なのかはプレイヤー同士で相談して決めること。',\n            'ゾッコン：相手は、唯一無二の相棒だ。いつから相棒なのかはプレイヤー同士で相談して決めること。',\n            '犬猿：相手とは、犬猿の仲である。犬猿の仲であるが、なぜ共に行動するのかはプレイヤー同士で相談して決めること。'\n          ]\n        ),\n        'ST' => DiceTable::Table.new(\n          '場面表',\n          '1D10',\n          [\n            'サ店（喫茶店）',\n            'クラブ',\n            '工業団地',\n            '神社／教会',\n            '学校',\n            '埠頭',\n            '繁華街',\n            'ゲーセン',\n            '公園',\n            '河原'\n            # 特殊な場合のみ発生する\n            # '病院'\n          ]\n        ),\n        'HT' => DiceTable::Table.new(\n          'ハプニング表',\n          '1D10',\n          [\n            '単車ドロ：愛車を盗まれる。次の自身の手番を迎えるまで、愛車が１台使用不能になる。所有している愛車が複数ある場合はランダムに１台を選ぶ。',\n            '職質：サツにドウグを取り上げられる。次の自身の手番を迎えるまで、素手を除くドウグが１つ使用不能になる。所有しているドウグが複数ある場合はランダムに１つを選ぶ。',\n            '不調：どうにも愛車やドウグが体になじまない次の判定の成功段階がー１される。',\n            '乱闘：不良との喧嘩に巻き込まれた。PC は1d10 点のダメージを受ける。',\n            '大人：悪辣な大人に遭遇して怒りが募る。PC は不良度が1d10 点上昇する',\n            '仲違い：つまらないことで喧嘩になって友情に亀裂が入る。場面に登場している【関係】を結んでいるキャラクターの中からランダムに対象を1 人選ぶ。シナリオが終了するまで対象との【関係】が失われる。',\n            '悪名：ボスの悪名が広がることによって自然とボスの取り巻きが増える。次の戦闘フェイズにモブが敵として1 人参加する。モブの種類はGM が決定する。',\n            '凶暴化：ボスの思考が先鋭化して凶悪になる。シナリオが終了するまでボスが与えるダメージを+2 する。この効果は累積するが、上昇した能力値は戦力には影響しない。',\n            '警戒：ボスは自身の周りでうごめく不穏な気配に警戒を強める。ボスの【HP 最大値】と【HP 現在値】を+10 する。この効果は累積する。',\n            '不運：ツキがなくなってきた気がする...。ラッキーナンバーの数値が２下がる（最低１）。すでにラッキーナンバーを使用済みであれば効果を受けない。'\n          ]\n        ),\n        'DT' => DiceTable::Table.new(\n          '闇堕ち表',\n          '1D10',\n          [\n            '出奔：すべての人間関係を捨ててどこか遠くへ旅に出る。',\n            '半グレ：半グレ集団とつるむようになり、悪事に手を染めるようになる。',\n            '指名手配：重大な犯罪を起こして指名手配されて逃亡者となる。',\n            '事故：大事故に遭い意識不明の重体となり長期入院する。',\n            'ヤク中：薬物中毒者となり、薬を得るためなら何でもするようになる。',\n            '借金：イカれた人間を信奉するようになり多額の借金を背負わされる。',\n            '傀儡：悪意を持って人間を利用しようとする勢力に祭り上げられ傀儡と化す。',\n            '身代わり：犯罪を犯した人間の身代わりにされて追われる身となる。',\n            '逮捕：度を越えた暴力沙汰を度々起こして警察に逮捕される。',\n            '失踪：ヤバい事件に首を突っ込んで謎の失踪を遂げる。'\n          ]\n        )\n      }.freeze\n\n      register_prefix('YD', TABLES.keys)\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:YankeeMustDie>", "initialize", "command", "self", "@sort_barabara_dice", "@sides_implicit_d", "10", "eval_game_system_specific_command", "$ret_or_1", "check_action", "roll_tables", "TABLES", "parser", "Command::Parser", "Command", "new", "@round_type", "restrict_cmp_op_to", "parsed", "parse", "dice_all", "loop", "block in check_action", "block (2 levels) in check_action", "dice_list", "@randomizer", "roll_barabara", "3", "sort", "push", "uniq", "one?", "achievement_value", "flatten", "sum", "modify_number", "<=", "9", "success_level", "0", "19", "1", "29", "2", "39", "49", "4", "59", "5", "69", "6", "79", "7", "89", "8", "99", "cmp_op", "is_success", ">", "target_number", "is_failure", "!", "success_message", ">=", "dice_to_message_arr", "each", "arr", "append", "join", "sequence", "to_s", "format", "tap", "Result", "r", "text=", "success=", "failure=", "DiceTable::Table", "DiceTable", "freeze", "register_prefix", "keys", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,eAAL;QAGA,gCAAOA,WAAP;QAGA,oCAAWA,WAAX;QAEA,wCACNA,WADqB,GAErBA,WAFqB,GAGrBA,4BAHqB,GAIrBA,mCAJqB,GAKrBA,iBALqB,GAMrBA,IANqB,GAOrBA,WAPqB,GAQrBA,mEARqB,GASrBA,yEATqB,GAUrBA,IAVqB,GAWrBA,SAXqB,GAYrBA,WAZqB,GAarBA,WAbqB,GAcrBA,cAdqB,GAerBA,YAfM;;AAkBAC,QAAAA,0BAAAA,sBAAeC,OAAfD;AAAAA,UAAAA;;UAAAA;;UACE,OAAAE,IAAA,EAAA,0DAAA,cAAA,EAAA,CAAMD,OAAN,CAAA,EAAA,IAAA;UACAE,0BAAsB;UACtBH,OAAAI,CAAAA,wBAAoBC,EAApBD;QAHFJ,CAAAA;;AAMAM,QAAAA,iDAAAA,6CAAsCL,OAAtCK;AAAAA,UAAAA;;UACE,OAAO,CAAA,QAAAC,CAAAA,YAAAL,IAAAM,cAAAA,CAAaP,OAAbO,CAAAD,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAyBL,IAAAO,aAAAA,CAAYR,OAAZ,EAAqBS,YAArBD,CAAzB,CAAA;QADTH,CAAAA;;AAIAE,QAAAA,4BAAAA,wBAAiBP,OAAjBO;AAAAA,UAAAA;;;UACEG,SAASC,IAAAC,aAAAD,WAAeE,KAAAA,CAAKN,IAApB,EAA0B,wBAAA,cAAYO,eAAZ,EAAXD,CACAE,oBAAAA,CAAoB,IADnC,EACwC,GADxC,EAC4C,GAA7BA;UACxBC,SAASN,MAAMO,OAAAA,CAAOjB,OAAPiB;UACf,KAAA,QAAOD,MAAP,CAAA;YACE,OAAO;UADT;UAIAE,WAAW;UACXC,YAAAA,MAAAA,IAAAA,4BAAAA,EAAAA,OAAAA,MAAAlB,IAAAkB,QAAAA,EAAAA,EAAAA,EAAAC,aAAAA,EAAAC;AAAAA;;;YACEC,YAAYC,eAAWC,eAAAA,CAAeC,CAA1B,EAA6BrB,EAAlBoB,CAAqBE,MAAAA,CAAAA;YAC5CR,QAAQS,MAAAA,CAAML,SAANK;YACR,IAAA,QAAaL,SAASM,MAAAA,CAAAA,CAAKC,SAAAA,CAAAA,CAA3B,CAAA;cAtDVR,OAAA;YAsDU;cAAA,QAAA,QAAA;YAAA,EAHFD,CAAAA,GAAAA,SAAAA,CAAAD,CAAAA;YAAAA;YAAAA;UAAAA,CAAAA;UAMAW,oBAAoBZ,QAAQa,SAAAA,CAAAA,CAAQC,KAAAA,CAAKhB,MAAMiB,eAAAA,CAAAA,CAAXD;UACpC,IAAA,QAAqBE,OAAlBJ,iBAAkBI,EAAGC,CAAHD,CAArB,CAAA;YACEE,gBAAgBC;UADlB,OAEA,IAAA,QAAwBH,OAAlBJ,iBAAkBI,EAAGI,EAAHJ,CAAxB,CAAA;YACEE,gBAAgBG;UADlB,OAEA,IAAA,QAAwBL,OAAlBJ,iBAAkBI,EAAGM,EAAHN,CAAxB,CAAA;YACEE,gBAAgBK;UADlB,OAEA,IAAA,QAAwBP,OAAlBJ,iBAAkBI,EAAGQ,EAAHR,CAAxB,CAAA;YACEE,gBAAgBX;UADlB,OAEA,IAAA,QAAwBS,OAAlBJ,iBAAkBI,EAAGS,EAAHT,CAAxB,CAAA;YACEE,gBAAgBQ;UADlB,OAEA,IAAA,QAAwBV,OAAlBJ,iBAAkBI,EAAGW,EAAHX,CAAxB,CAAA;YACEE,gBAAgBU;UADlB,OAEA,IAAA,QAAwBZ,OAAlBJ,iBAAkBI,EAAGa,EAAHb,CAAxB,CAAA;YACEE,gBAAgBY;UADlB,OAEA,IAAA,QAAwBd,OAAlBJ,iBAAkBI,EAAGe,EAAHf,CAAxB,CAAA;YACEE,gBAAgBc;UADlB,OAEA,IAAA,QAAwBhB,OAAlBJ,iBAAkBI,EAAGiB,EAAHjB,CAAxB,CAAA;YACEE,gBAAgBgB;UADlB,OAEA,IAAA,QAAwBlB,OAAlBJ,iBAAkBI,EAAGmB,EAAHnB,CAAxB,CAAA;YACEE,gBAAgBD;UADlB;YAGEC,gBAAgBhC;UAHlB;UAMA,IAAA,MAAGY,MAAMsC,QAAAA,CAAAA,CAAT,EAAoB,GAApB,CAAA;;YACEC,aAA2BC,OAAdpB,aAAcoB,EAAExC,MAAMyC,eAAAA,CAAAA,CAARD;YAC3BE,aAAcH,UAADI,MAAAA,CAAAA;YACbC,kBAAkB,CAAA,QAAAL,UAAA,CAAA,GAAA,CAAahD,IAAb,IAAA,CAAoBA,IAApB,CAAA;UAHpB,OAIA,IAAA,MAAMS,MAAMsC,QAAAA,CAAAA,CAAZ,EAAuB,IAAvB,CAAA;;YACEC,aAA2BM,OAAdzB,aAAcyB,EAAG7C,MAAMyC,eAAAA,CAAAA,CAATI;YAC3BH,aAAcH,UAADI,MAAAA,CAAAA;YACbC,kBAAkB,CAAA,QAAAL,UAAA,CAAA,GAAA,CAAahD,IAAb,IAAA,CAAoBA,IAApB,CAAA;UAHpB;;YAKEgD,aAAa;YACbG,aAAa;YACbE,kBAAkB;UAPpB;UAUAE,sBAAsB;UACdC,MAAR7C,QAAQ6C,QAAAA,EAAAA,EAAAA,EAAR3C,aAAkB4C,GAAlB5C;;YAAkB;YAChBC,OAAAyC,mBAAmBG,QAAAA,CAAQ,EAAA,GAAA,CAAGD,GAAGhC,KAAAA,CAAAA,CAAN,CAAA,GAAWX,GAAX,GAAA,CAAc2C,GAAGE,MAAAA,CAAM7C,GAAN6C,CAAjB,CAAA,GAA4B7C,GAApC4C,EADrB7C,CAAQ2C;UAIRI,WAAW,CACTnD,MAAMoD,MAAAA,CAAAA,CADG,EAETnE,IAAAoE,QAAAA,CAAO,EAAA,GAAA,CAAGP,mBAAmBI,MAAAA,CAAM3D,KAAN2D,CAAtB,CAAA,GAAmC3D,MAA1C,EAAiDS,MAAMiB,eAAAA,CAAAA,CAAvDoC,CAFS,EAGTvC,iBAHS,EAIRvB,MAAD,GAAA,CAAO6B,aAAP,CAJS;UAOX,IAAA,QAAGwB,eAAH,CAAA;YACEO,QAAQF,QAAAA,CAAQL,eAARK;UADV;UAIA1D,OAAU+D,MAAVC,YAAM1D,KAAAA,CAAAA,CAAIyD,OAAAA,EAAAA,EAAAA,EAAVlD,aAAmBoD,CAAnBpD,EAAAC;;;YAAmB;YACjBmD,CAACC,UAAAA,CAAQN,QAAQD,MAAAA,CAAM7C,KAAN6C,CAAhBO;YACDD,CAACE,aAAAA,CAAWnB,UAAXmB;YACDrD,OAACsD,MAAAA,CAAWjB,UAAXiB,CAAAA,EAAAA,MAADH,CAACG,YAAAA,EAAAA,EAAAA,CAAAA,EAAAA,mBAHHvD,CAAUkD;QAtEZ/D,CAAAA;QA6EA,kCAAS,kCAAA,MACCqE,IAAAC,eAAAD,UAAgB/D,KAAAA,CACtBf,KADM,EAENA,MAFM,EAGN,CACEA,qDADF,EAEEA,kDAFF,EAGEA,uDAHF,EAIEA,uDAJF,EAKEA,sDALF,EAMEA,uDANF,EAOEA,wDAPF,EAQEA,8CARF,EASEA,gDATF,EAUEA,wDAVF,CAHsBe,CADjB,EAAA,MAiBC+D,IAAAC,eAAAD,UAAgB/D,KAAAA,CACtBf,KADM,EAENA,MAFM,EAGN,CACEA,SADF,EAEEA,KAFF,EAGEA,MAHF,EAIEA,OAJF,EAKEA,IALF,EAMEA,IANF,EAOEA,KAPF,EAQEA,MARF,EASEA,IATF,EAUEA,IAVF,CAHsBe,CAjBjB,EAAA,MAmCC+D,IAAAC,eAAAD,UAAgB/D,KAAAA,CACtBf,QADM,EAENA,MAFM,EAGN,CACEA,qEADF,EAEEA,iFAFF,EAGEA,uCAHF,EAIEA,uCAJF,EAKEA,uCALF,EAMEA,iGANF,EAOEA,0EAPF,EAQEA,gFARF,EASEA,qEATF,EAUEA,yEAVF,CAHsBe,CAnCjB,EAAA,MAmDC+D,IAAAC,eAAAD,UAAgB/D,KAAAA,CACtBf,MADM,EAENA,MAFM,EAGN,CACEA,4BADF,EAEEA,mCAFF,EAGEA,+BAHF,EAIEA,4BAJF,EAKEA,kCALF,EAMEA,kCANF,EAOEA,qCAPF,EAQEA,iCARF,EASEA,8BATF,EAUEA,2BAVF,CAHsBe,CAnDjB,EAmERiE,QAAAA,CAAAA,CAnED;QAqEAhF,OAAAG,IAAA8E,iBAAAA,CAAgBjF,IAAhB,EAAsBW,YAAMuE,MAAAA,CAAAA,CAA5BD;MAxLFjF,GAAAA,WAAAA,EAAsBmF,UAAtBnF;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}]}